// Solution
function projectDocument(document, projection) {
  const projectedDocument = {}; // Create a new object to store the projected document
  Object.keys(projection).forEach(key => {
    const parts = key.split('.'); // Split the key into nested parts
    let current = projectedDocument;
    for (let i = 0; i < parts.length; i++) {
      if (i === parts.length - 1) { // If this is the last part, set the value
        current[parts[i]] = document[parts[i]];
      } else { // Otherwise, create a new object if it doesn't exist
        current[parts[i]] = current[parts[i]] || {};
        current = current[parts[i]];
      }
    }
  });
  return projectedDocument;
}

