class Solution:
    def projectDocument(self, document, projection) -> dict:
        projected_document = {}
        for key in projection:
            parts = key.split('.')
            current = projected_document
            for i in range(len(parts)):
                if i == len(parts) - 1:
                    current[parts[i]] = document[parts[i]]
                else:
                    current = current.setdefault(parts[i], {})
        return projected_document
